} from "@/components/lemma/records-detail"

export type DetailAction = RecordAction

export interface LemmaDetailPanelProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string
  enabled?: boolean
  mode?: RecordDetailMode
  variant?: RecordDetailVariant
  layout?: RecordDetailLayout
